    edges.sort((a, b) => a[2] - b[2]);

    // Union-Find (Disjoint Set Union) data structure
    const parent: number[] = Array(n).fill(0);
    const rank: number[] = Array(n).fill(0);

    function find(u: number): number {
        if (parent[u] !== u) {
            parent[u] = find(parent[u]);
        }
        return parent[u];
    }

    function union(u: number, v: number): boolean {
        const rootU = find(u);
        const rootV = find(v);
        if (rootU === rootV) return false;
        if (rank[rootU] < rank[rootV]) {
            parent[rootU] = rootV;
        } else {
            parent[rootV] = rootU;
            if (rank[rootU] === rank[rootV]) {
                rank[rootU]++;
            }
        }
        return true;
    }

    // Initialize parent array
    for (let i = 0; i < n; i++) {
        parent[i] = i;
    }

    // Keep track of the number of connected components
    let components = n;

    // Iterate through edges in order of increasing time
    for (const [u, v, time] of edges) {
        // If the edge connects two different components, merge them
        if (union(u, v)) {
            components--;
        }
        // Check if we have at least k components
        if (components <= k) {
            return time;
        }
    }

    // If we haven't found a time yet, return 0 (no edges to remove)
    return 0;
}

